parameters.jsonBody:
={
  "embeds": [
    {
      "title": "🔔 Retour Support — {{ $json.ticket_number }}",
      "color": 16711790,
      "fields": [
        { "name": "🏢 Client", "value": "{{ $json.company_name }}", "inline": true },
        { "name": "📋 Ticket", "value": "{{ $json.ticket_number }}", "inline": true },
        { "name": "🏷️ Catégorie", "value": "{{ $json.category }}", "inline": true },
        { "name": "⚡ Priorité", "value": "{{ $json.priority }}", "inline": true },
        { "name": "📝 Objet", "value": "{{ $json.subject }}", "inline": false },
        { "name": "👤 Assigné à", "value": "{{ $json.assigned_to_name || 'Non assigné' }}", "inline": true },
        { "name": "📊 Statut", "value": "{{ $json.status }}", "inline": true },
        { "name": "💬 Notes admin", "value": "{{ $json.admin_notes || 'Aucune' }}", "inline": false }
      ],
      "footer": { "text": "Adamkom CRM — Support" },
      "timestamp": "{{ $json.timestamp }}"
    }
  ]
}
